/* ─── Vehicle SVGs ─── */
function BikeSvg({ color = "#fff", size = 28 }: { color?: string; size?: number }) {
  return (
    <svg width={size} height={size * 0.6} viewBox="0 0 40 24" fill="none">
      <circle cx="8" cy="18" r="5" stroke={color} strokeWidth="2" />
      <circle cx="32" cy="18" r="5" stroke={color} strokeWidth="2" />
      <path d="M8 18 L16 8 L26 8 L32 18" stroke={color} strokeWidth="2" fill="none" />
      <path d="M20 8 L22 4 L28 4" stroke={color} strokeWidth="1.5" />
    </svg>
  );
}

function CarSvg({ color = "#fff", size = 36 }: { color?: string; size?: number }) {
  return (
    <svg width={size} height={size * 0.55} viewBox="0 0 48 26" fill="none">
      <rect x="4" y="12" width="40" height="10" rx="3" stroke={color} strokeWidth="1.5" />
      <path d="M10 12 L14 4 L34 4 L38 12" stroke={color} strokeWidth="1.5" fill="none" />
      <circle cx="12" cy="22" r="4" stroke={color} strokeWidth="2" />
      <circle cx="36" cy="22" r="4" stroke={color} strokeWidth="2" />
    </svg>
  );
}

function AutoSvg({ color = "#fff", size = 32 }: { color?: string; size?: number }) {
  return (
    <svg width={size} height={size * 0.65} viewBox="0 0 40 26" fill="none">
      <circle cx="10" cy="20" r="5" stroke={color} strokeWidth="2" />
      <circle cx="30" cy="20" r="5" stroke={color} strokeWidth="2" />
      <path d="M10 20 L10 10 L20 6 L32 10 L32 20" stroke={color} strokeWidth="1.5" fill="none" />
      <path d="M10 10 L20 10" stroke={color} strokeWidth="1.2" />
    </svg>
  );
}

